#include <stdio.h>

int main(void) {
    FILE *tmp = tmpfile();
    if (!tmp) {
        perror("tmpfile");
        return 1;
    }

    /* Ecrire 5 entiers */
    for (int i = 1; i <= 5; i++)
        fprintf(tmp, "%d\n", i * i);

    /* Revenir au debut */
    rewind(tmp);

    /* Relire et afficher */
    int val;
    printf("Squares:\n");
    while (fscanf(tmp, "%d", &val) == 1)
        printf("  %d\n", val);

    fclose(tmp);
    return 0;
}

