    FILE *t = tmpfile();
    if (!t) return;
    fprintf(t, "alpha\nbeta\ngamma\n");
    rewind(t);
    char buf[64];
    while (fgets(buf, sizeof(buf), t)) {
        buf[strcspn(buf, "\n")] = 0;
        printf("Read: %s\n", buf);
